import (
	context "context"
	fern "github.com/url-form-encoded/fern"
	fernclient "github.com/url-form-encoded/fern/client"
)

client := fernclient.NewClient()
response, err := client.SubmitFormData(
	context.TODO(),
	&fern.PostSubmitRequest{
		Username: "johndoe",
		Email:    "john@example.com",
	},
)

import (
	context "context"
	fern "github.com/url-form-encoded/fern"
	fernclient "github.com/url-form-encoded/fern/client"
)

client := fernclient.NewClient()
response, err := client.GetToken(
	context.TODO(),
	&fern.TokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
	},
)
